functions.longDescription:
JSON for Modern C++ provides a value type plus parse and serialization helpers. Keep parsing of untrusted content inside try/catch or explicitly disable exceptions and check the result.

Examples retained from the previous pack:

```cpp
// Dependency: nlohmann/json
#include <nlohmann/json.hpp>

using json = nlohmann::json;
```

```cpp
#include <fstream>
#include <nlohmann/json.hpp>
#include <stdexcept>

using json = nlohmann::json;

std::ifstream input("config.json");
if (!input)
{
    throw std::runtime_error("Unable to open config.json");
}

json config = json::parse(input);
```

```cpp
const std::string host = config.at("host").get<std::string>();
const int port = config.value("port", 8080);
const bool enabled = config.value("enabled", true);

if (config.contains("timeout_ms"))
{
    timeoutMs = config.at("timeout_ms").get<int>();
}
```

```cpp
#include <fstream>
#include <nlohmann/json.hpp>

using json = nlohmann::json;

json report = {
    {"status", "ok"},
    {"temperature", 24.5},
    {"samples", {1, 2, 3}}
};

std::ofstream output("report.json");
output << report.dump(4) << '\n';
```

```cpp
try
{
    json config = json::parse(input);
}
catch (const nlohmann::json::parse_error &error)
{
    std::cerr << "JSON parse error near byte " << error.byte
              << ": " << error.what() << '\n';
}
```

```cpp
json config = json::parse(content, nullptr, false);
if (config.is_discarded())
{
    std::cerr << "Invalid JSON configuration\n";
    return false;
}
```

```cpp
struct DeviceConfig
{
    std::string name;
    int channel = 0;
};

void to_json(json &j, const DeviceConfig &config)
{
    j = json{{"name", config.name}, {"channel", config.channel}};
}

void from_json(const json &j, DeviceConfig &config)
{
    j.at("name").get_to(config.name);
    j.at("channel").get_to(config.channel);
}
```

