#include <fcntl.h>
#include <stdexcept>
#include <sys/mman.h>
#include <sys/stat.h>
#include <unistd.h>

const int fd = ::open("data.bin", O_RDONLY | O_CLOEXEC);
if (fd < 0) throw std::runtime_error("open failed");

struct stat info {};
if (::fstat(fd, &info) != 0) throw std::runtime_error("fstat failed");

void *mapping = ::mmap(nullptr, static_cast<std::size_t>(info.st_size),
                       PROT_READ, MAP_PRIVATE, fd, 0);
if (mapping == MAP_FAILED) throw std::runtime_error("mmap failed");

// Use static_cast<const std::byte *>(mapping) here.

::munmap(mapping, static_cast<std::size_t>(info.st_size));
::close(fd);

