POSIX serial-port setup normally combines open, tcgetattr, cfsetispeed, cfsetospeed and tcsetattr.

Workflow examples retained from the previous pack:

```cpp
#ifndef _WIN32
#include <fcntl.h>
#include <termios.h>
#include <unistd.h>

int serial = open("/dev/ttyUSB0", O_RDWR | O_NOCTTY);
termios tty{};
tcgetattr(serial, &tty);
cfsetispeed(&tty, B115200);
cfsetospeed(&tty, B115200);
tty.c_cflag = (tty.c_cflag & ~CSIZE) | CS8;
tty.c_cflag |= CLOCAL | CREAD;
tty.c_cflag &= ~(PARENB | CSTOPB | CRTSCTS);
tty.c_lflag = 0;
tty.c_iflag = 0;
tty.c_oflag = 0;
tcsetattr(serial, TCSANOW, &tty);
#endif
```

Synchronous libusb workflows remain easy to follow but block the caller. Keep event-loop or worker-thread considerations in mind.

Workflow examples retained from the previous pack:

```cpp
#include <libusb.h>
#include <stdexcept>

libusb_context *context = nullptr;
if (libusb_init(&context) != 0)
{
    throw std::runtime_error("libusb_init failed");
}

libusb_device_handle *device = libusb_open_device_with_vid_pid(context, 0x1234, 0x5678);
if (!device)
{
    libusb_exit(context);
    throw std::runtime_error("USB device not found");
}

libusb_claim_interface(device, 0);
```

```cpp
unsigned char buffer[512]{};
int transferred = 0;

const int result = libusb_bulk_transfer(
    device,
    0x81, // endpoint IN
    buffer,
    sizeof(buffer),
    &transferred,
    1000); // timeout ms

if (result != 0)
{
    HandleUsbError(result);
}
```

```cpp
unsigned char data[64]{};

