cpp-httplib offers a compact embedded HTTP server. The previous endpoint examples are retained here.

Workflow examples retained from the previous pack:

```cpp
#include "httplib.h"
#include <nlohmann/json.hpp>

httplib::Server server;

server.Get("/api/status", [](const httplib::Request &, httplib::Response &response)
{
    nlohmann::json body = {
        {"ready", true},
        {"temperature", 24.5}
    };
    response.set_content(body.dump(), "application/json");
});

server.listen("0.0.0.0", 8080);
```

```cpp
server.Post("/api/command", [](const httplib::Request &request, httplib::Response &response)
{
    try
    {
        const nlohmann::json body = nlohmann::json::parse(request.body);
        const std::string command = body.at("command").get<std::string>();
        ExecuteCommand(command);
        response.set_content(R"({"ok":true})", "application/json");
    }
    catch (const std::exception &error)
    {
        response.status = 400;
        response.set_content(nlohmann::json{{"ok", false}, {"error", error.what()}}.dump(),
                             "application/json");
    }
});
```

```cpp
httplib::Server server;
server.set_mount_point("/", "./wwwroot");

server.set_post_routing_handler([](const httplib::Request &, httplib::Response &response)
{
    response.set_header("Access-Control-Allow-Origin", "http://localhost:5173");
});
```

```cpp
httplib::Server server;

std::jthread webThread([&server]
{
    server.listen("127.0.0.1", 8080);
});

// During application shutdown:
server.stop();
```

