Exclusive owning smart pointer.

Examples previously provided as snippets:

```cpp
#include <memory>

auto device = std::make_unique<Device>(42);
device->Open();
```

```cpp
#include <memory>

auto samples = std::make_unique<double[]>(count);
samples[0] = 1.0;
```

```cpp
#include <memory>

void Install(std::unique_ptr<Device> device);
auto device = std::make_unique<Device>();
Install(std::move(device));
// device is now empty
```

```cpp
#include <memory>

std::unique_ptr<const Device> pointerToConst = std::make_unique<Device>();
const std::unique_ptr<Device> constPointer = std::make_unique<Device>();
```

```cpp
/*
 std::unique_ptr<T> : one owner; preferred owning pointer
 std::shared_ptr<T> : several genuine owners
 std::weak_ptr<T>   : observer of shared_ptr-managed object
 T *                : optional non-owning observer / interop
 T &                : mandatory non-owning alias
 std::vector<T>     : preferred resizable owned sequence
*/
```

