#include <windows.h>

BOOL APIENTRY DllMain(HMODULE hModule, DWORD ul_reason_for_call, LPVOID lpReserved)
{
    (void)lpReserved;

    if (ul_reason_for_call == DLL_PROCESS_ATTACH)
    {
        /* Use only when DLL_THREAD_ATTACH / DLL_THREAD_DETACH callbacks are not required. */
        DisableThreadLibraryCalls({{module}});
    }

    return TRUE;
}

#include <windows.h>
#include <stdexcept>

class UniqueModule
{
public:
    explicit UniqueModule(HMODULE module = nullptr) noexcept : module_(module) {}
    ~UniqueModule() { if (module_) FreeLibrary(module_); }
    UniqueModule(const UniqueModule &) = delete;
    UniqueModule &operator=(const UniqueModule &) = delete;
    HMODULE get() const noexcept { return module_; }
private:
    HMODULE module_ = nullptr;
};

using PluginRunFn = int (WINAPI *)(int value);

UniqueModule module(LoadLibraryExW(
    {{libraryPath}},
    nullptr,
    LOAD_LIBRARY_SEARCH_DLL_LOAD_DIR | LOAD_LIBRARY_SEARCH_DEFAULT_DIRS));
if (!module.get())
    throw std::runtime_error("LoadLibraryExW failed");

auto run = reinterpret_cast<PluginRunFn>(
    GetProcAddress(module.get(), {{procedureName}}));
if (!run)
    throw std::runtime_error("GetProcAddress failed");

const int result = run({{argument}});

