QTimer integrates delays with the Qt event loop. Avoid blocking the GUI thread.

Workflow examples retained from the previous pack:

```cpp
auto *timer = new QTimer(this);
timer->setInterval(250);
connect(timer, &QTimer::timeout, this, &MainWindow::pollDevice);
timer->start();
```

```cpp
using namespace std::chrono_literals;

QTimer::singleShot(500ms, this, [this]
{
    refreshMeasurements();
});
```

```cpp
auto *timer = new QTimer(this);
timer->setSingleShot(true);
timer->setInterval(750);
connect(timer, &QTimer::timeout, this, &MainWindow::retryConnection);
timer->start();
```

```cpp
timer_->setInterval(1000);
timer_->start();

// Later:
timer_->stop();
timer_->start(250); // Restarts with a 250 ms interval.
```

```cpp
if (timer_->isActive())
{
    qDebug() << "Remaining ms:" << timer_->remainingTime();
}
```

```cpp
