QLibrary loads shared libraries and resolves C-compatible exports. Preserve lifetime while function pointers are in use.

Workflow examples retained from the previous pack:

```cpp
#include <QCoreApplication>
#include <QDir>
#include <QLibrary>
#include <QDebug>

const QString libraryPath = QDir(QCoreApplication::applicationDirPath())
    .filePath("Scan_BLE_DLL.dll"); // Linux: libscan_ble.so

QLibrary library(libraryPath);
if (!library.load())
{
    qCritical() << "Unable to load" << libraryPath
                << ":" << library.errorString();
    return;
}

qInfo() << "Loaded:" << library.fileName();
```

```cpp
#include <QLibrary>
#include <stdexcept>

using ScanBleFn = int (*)(const char *deviceName, int timeoutMs);

QLibrary library("Scan_BLE_DLL");
if (!library.load())
{
    throw std::runtime_error(library.errorString().toStdString());
}

auto scanBle = reinterpret_cast<ScanBleFn>(library.resolve("ScanBle"));
if (!scanBle)
{
    throw std::runtime_error(library.errorString().toStdString());
}

const int result = scanBle("Sensor_A", 2000);
```

```cpp
#include <QLibrary>
#include <QString>

using InitFn = int (*)();
using ScanFn = int (*)(int timeoutMs);
using ShutdownFn = void (*)();

QLibrary library("Scan_BLE_DLL");
if (!library.load())
    throw std::runtime_error(library.errorString().toStdString());

auto init = reinterpret_cast<InitFn>(library.resolve("Ble_Init"));
auto scan = reinterpret_cast<ScanFn>(library.resolve("Ble_Scan"));
auto shutdown = reinterpret_cast<ShutdownFn>(library.resolve("Ble_Shutdown"));

if (!init || !scan || !shutdown)
{
    throw std::runtime_error(
        QString("Incomplete DLL API: %1").arg(library.errorString()).toStdString());
}
