```cpp
#include <QString>

#if defined(Q_OS_WIN)
const QString libraryName = "Scan_BLE_DLL.dll";
#elif defined(Q_OS_LINUX)
const QString libraryName = "libScan_BLE_DLL.so";
#elif defined(Q_OS_MACOS)
const QString libraryName = "libScan_BLE_DLL.dylib";
#else
#error Unsupported platform
#endif
```

```cpp
#pragma once

#include <QLibrary>
#include <QString>

class BleDllLoader
{
public:
    using ScanFn = int (*)(const char *deviceName, int timeoutMs);

    explicit BleDllLoader(QString fileName)
        : library_(std::move(fileName))
    {
    }

    bool load()
    {
        if (!library_.load())
            return false;

        scan_ = reinterpret_cast<ScanFn>(library_.resolve("ScanBle"));
        return scan_ != nullptr;
    }

    QString errorString() const { return library_.errorString(); }
    bool isLoaded() const { return library_.isLoaded() && scan_ != nullptr; }

    int scan(const char *deviceName, int timeoutMs) const
    {
        return scan_ ? scan_(deviceName, timeoutMs) : -1;
    }

private:
    QLibrary library_;
    ScanFn scan_ = nullptr;
};
```

```cpp
#if defined(_WIN32)
#  define BLE_API extern "C" __declspec(dllexport)
#else
#  define BLE_API extern "C" __attribute__((visibility("default")))
#endif

